INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('european-summit-energy-policies-2030', 'European Summit: Leaders Approve Historic Energy Policies for 2030', 'The heads of government of the 27 EU member states have reached a historic agreement on energy policies that will reshape the continent\'s industrial landscape.', 'European leaders gathered in Brussels have unanimously approved an unprecedented package of energy measures set to radically transform how the continent produces and consumes energy by 2030. The agreement, the result of months of intensive negotiations, includes increasing the share of renewable energy to 45% of the total energy mix, reducing CO₂ emissions by 55% compared to 1990 levels, and public investments exceeding 800 billion euros in green infrastructure.', 'World', '#E8A020', 'Marco Ferretti', 'Correspondent from Brussels', 1, 1, 5, 'https://d2xsxph8kpxj0f.cloudfront.net/310519663399083273/3dAGBac6MGitvNrWVvmyAK/bishouy-hero-world-YhM6ksz8FapgLsXA57BfrG.webp', '[\"Europe\", \"Energy\", \"Climate\", \"Politics\"]', NOW(), NOW(), NOW());

INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('artificial-intelligence-cancer-diagnosis', 'AI Diagnoses Tumors with Precision Exceeding Doctors: Study Changes Everything', 'Research published in Nature Medicine shows that new artificial intelligence models surpass the diagnostic accuracy of oncologists in 12 types of cancer.', 'An international consortium of researchers has published results from a multi-year study that could redefine the future of oncology medicine. The artificial intelligence system developed jointly by three European universities demonstrated diagnostic accuracy of 94.7% in early detection of 12 tumor types, exceeding the average of specialized oncologists by 12%.', 'Technology', '#2980B9', 'Giulia Marchetti', 'Science & Technology Editor', 1, 0, 6, 'https://d2xsxph8kpxj0f.cloudfront.net/310519663399083273/3dAGBac6MGitvNrWVvmyAK/bishouy-hero-tech-84qN2YaQfKXA65us9qtHUm.webp', '[\"Artificial Intelligence\", \"Medicine\", \"Research\", \"Oncology\"]', NOW(), NOW(), NOW());

INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('financial-markets-record-volatility', 'Financial Markets: Record Volatility, Fund Managers Take Defensive Measures', 'The VIX index reached three-year highs as major stock markets register daily swings exceeding 3%.', 'Global financial markets are experiencing exceptional volatility, with the fear index VIX touching 38 — the highest level since 2023 — and major stock exchanges registering daily swings exceeding 3%. Behind the turbulence lies a combination of factors: uncertainty about monetary policies from major central banks, geopolitical tensions in various regions, and mixed macroeconomic data from advanced economies.', 'Economy', '#27AE60', 'Luca Bianchi', 'Financial Analyst', 1, 0, 4, 'https://d2xsxph8kpxj0f.cloudfront.net/310519663399083273/3dAGBac6MGitvNrWVvmyAK/bishouy-hero-economy-W5ThKktzEpiMxWv3GgWEet.webp', '[\"Finance\", \"Markets\", \"Economy\", \"Investments\"]', NOW(), NOW(), NOW());

INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('venice-film-festival-cinema-awards', 'Venice Film Festival: Cinema from the Global South Triumphs', 'The Golden Lion goes to a Colombian film telling the story of an indigenous community. The jury rewards diversity and narrative authenticity.', 'The 83rd Venice International Film Festival concluded with an awards ceremony marking a historic turning point: for the first time, the Golden Lion went to a film entirely produced in Colombia, "Tierra Roja" by Camila Restrepo, a work depicting the resistance of an Amazonian indigenous community against natural resource exploitation.', 'Culture', '#8E44AD', 'Sofia Romano', 'Film Critic', 0, 0, 4, 'https://d2xsxph8kpxj0f.cloudfront.net/310519663399083273/3dAGBac6MGitvNrWVvmyAK/bishouy-hero-culture-GQHAvUwFQRKWd5UgrsBmXZ.webp', '[\"Cinema\", \"Venice\", \"Culture\", \"Arts\"]', NOW(), NOW(), NOW());

INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('government-tax-reform-40-billion', 'Tax Reform: Government Presents 40-Billion-Euro Plan', 'The Economy Minister outlines details of the plan providing income tax reduction for middle-income earners and introducing flat tax for businesses.', 'The government presented today in the Council of Ministers the most ambitious tax reform plan in the past twenty years. The package, worth a total of 40 billion euros distributed over three years, includes significant income tax reduction for earners between 28,000 and 55,000 euros annually, introduction of a 15% flat tax for businesses with turnover up to 5 million euros, and enhanced deductions for families with children.', 'Politics', '#C0392B', 'Antonio Esposito', 'Parliamentary Correspondent', 0, 0, 5, 'https://images.unsplash.com/photo-1529107386315-e1a2ed48a620?w=800&q=80', '[\"Tax\", \"Government\", \"Economy\", \"Politics\"]', NOW(), NOW(), NOW());

INSERT INTO articles (slug, title, excerpt, content, category, categoryColor, author, authorRole, featured, breaking, readTime, image, tags, publishedAt, createdAt, updatedAt) VALUES ('champions-league-semifinals-benfica', 'Champions League: Four Semifinalists Confirmed. Benfica Surprise, Bayern Out', 'Benfica eliminates Bayern Munich on penalties in a historic night for Portuguese football. Real Madrid, PSG, and Inter complete the picture.', 'An unforgettable night of football has determined the four Champions League semifinalists. The most striking result comes from Lisbon, where Benfica eliminated Bayern Munich on penalties after an extraordinary match that ended 2-2 after extra time.', 'Sports', '#E67E22', 'Roberto Conti', 'Sports Editor', 0, 0, 3, 'https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=800&q=80', '[\"Champions League\", \"Football\", \"Sports\", \"Benfica\"]', NOW(), NOW(), NOW());

